// Format laporan fraud dari hasil analisis
const data = $input.first().json;
const fraudList = data.results.filter(r => r.verdict === 'FRAUD');
const warnList  = data.results.filter(r => r.verdict === 'WARNING');

let report = `🚨 FRAUD ALERT — ${new Date().toLocaleString('id-ID')}\n`;
report += `━━━━━━━━━━━━━━━━━━━━━━\n`;
report += `Total nasabah dicek: ${data.total}\n`;
report += `🔴 FRAUD   : ${data.fraud} nasabah\n`;
report += `🟡 WARNING : ${data.warning} nasabah\n`;
report += `🟢 AMAN    : ${data.aman} nasabah\n\n`;

if (fraudList.length > 0) {
  report += `🔴 DAFTAR FRAUD:\n`;
  fraudList.forEach(r => {
    report += `  • ${r.customer} (ID:${r.customer_id}) — Score: ${r.score}/100\n`;
    report += `    ${r.action}\n`;
  });
  report += `\n`;
}

if (warnList.length > 0) {
  report += `🟡 DAFTAR WARNING:\n`;
  warnList.forEach(r => {
    report += `  • ${r.customer} (ID:${r.customer_id}) — Score: ${r.score}/100\n`;
  });
}

return [{ json: { report, fraud_count: data.fraud, warning_count: data.warning, raw: data } }];

// Tulis log ke file
const fs = require('fs');
const data = $input.first().json;
const logPath = 'C:/Users/Russel/ai-demo/data/n8n_fraud_log.txt';

const line = `[${new Date().toLocaleString('id-ID')}] ` +
  `FRAUD:${data.fraud_count} WARNING:${data.warning_count}\n` +
  data.report + '\n' + '='.repeat(40) + '\n';

fs.appendFileSync(logPath, line, 'utf8');
console.log('Log ditulis:', logPath);

return [{ json: { logged: true, path: logPath, report: data.report } }];

